import React from 'react';
import CssBaseline from '@material-ui/core/CssBaseline';
import Sidebar from './components/Sidebar.js';
import Drawer from '@material-ui/core/Drawer';

import { makeStyles, useTheme } from "@material-ui/core/styles";
import { Route, Switch } from 'react-router-dom';
import Nexus from './views/Nexus';
import Compare from './views/Compare.js';
import Compile from './views/Compile.js';
import PlexusForecast from './views/PlexusForecast.js';
import JabilForecast from './views/JabilForecast.js';
import PlexusEmail from './views/PlexusEmail.js';
import Rescheduler from './views/Rescheduler.js';
import QuotationCompare from './views/QuotationCompare.js';
import QuotationCompile from './views/QuotationCompile.js';
import Uct from './views/Uct.js';
import Cei from './views/Cei.js';
import Ges from './views/Ges.js';
import QuotationModuleUpload from './views/QuotationModuleUpload.js';
import QuotationModuleDownload from './views/QuotationModuleDownload.js';
import PushtonPhoenix from './views/PushtonPhoenix.js';
import Stock from './views/Stock.js';


const drawerWidth = 240;

const useStyles = makeStyles((theme) => ({
  root: {
    display: 'flex',
    // fontFamily:'AirbnbCereal-Medium'
  },
  appBar: {
    width: `calc(100% - ${drawerWidth}px)`,
    marginLeft: drawerWidth,
  },
  drawer: {
    width: drawerWidth,
    flexShrink: 0,
  },
  drawerPaper: {
    width: drawerWidth,
    backgroundColor: '#2e4574',
    border: 'none'
  },
  content: {
    flexGrow: 1,
    backgroundColor: theme.palette.background.default,
    padding: theme.spacing(3),
  },
}));


function App() {
  const classes = useStyles();
  return (
    <div className={classes.root}>
      <CssBaseline />
      <nav className={classes.drawer} aria-label="navigation-tabs">
        <Drawer
          classes={{
            paper: classes.drawerPaper
          }}
          variant="permanent"
          open
        >
          <Sidebar />
        </Drawer>
      </nav>
      <main className={classes.content}>
        <div className={classes.toolbar} />
        <Switch>
          {/* <Route exact path="/file-automation" render={() => <div>WISELINK</div>} /> */}
          <Route path="/file-automation/plexus/jit" render={() => <Nexus />} />
          <Route path="/file-automation/plexus/forecast" render={() => <PlexusForecast />} />
          <Route path="/file-automation/plexus/email" render={() => <PlexusEmail />} />
          <Route path="/file-automation/jabil/forecast" render={() => <JabilForecast />} />
          <Route path="/file-automation/reschedule/oor_report" render={() => <Uct />} />
          <Route path="/file-automation/reschedule/ges_report" render={() => <Ges />} />
          <Route path="/file-automation/reschedule/cei_report" render={() => <Cei />} />
          <Route path="/file-automation/reschedule/general" render={() => <Rescheduler />} />
          <Route path="/file-automation/ecommerce/online-stock-pricing" render={() => <Compare />} />
          <Route path="/file-automation/ecommerce/compile" render={() => <Compile />} />
          <Route path="/file-automation/admin/transfer-quotation" render={() => <QuotationCompare />} />
          <Route path="/file-automation/admin/input-supplier-price" render={() => <QuotationCompile />} />
          <Route path="/file-automation/admin/quotation-upload" render={() => <QuotationModuleUpload />} />
          <Route path="/file-automation/admin/quotation-download" render={() => <QuotationModuleDownload />} />
          <Route path="/file-automation/comparator/pushton-phoenix" render={() => <PushtonPhoenix />} />
          <Route path="/file-automation/netcomponents" render={() => <Stock />} />
        </Switch>
      </main>
    </div>
  );
}

export default App;
