import React, { useState } from 'react';
import { useStyles } from '../styles'
import { Backdrop, CircularProgress, Input } from '@material-ui/core';
import axios from 'axios';

const QuotationCompile = () => {
    const classes = useStyles()
    const [loading, setLoading] = useState(false)
    const [inputFile, setInputFile] = useState(null)
    const [priceList, setPriceList] = useState(null)

    const uploadInput = (event) => {
        setInputFile(event.target.files[0])
    }

    const uploadPricelist = (event) => {
        setPriceList(event.target.files[0])
    }


    const postRequest = async () => {
        setLoading(true)

        if (inputFile == null || priceList == null) {
            alert('ensure all files have ben uploaded before proceeding')
            setLoading(false)
            return
        }

        const formData = new FormData();
        formData.append("file", inputFile);
        formData.append("price_list", priceList);

        try {
            await axios.post("https://wiselink-backend-r5t3r36gwq-as.a.run.app/update", formData,
                {
                    headers:
                    {
                        'Content-Disposition': "attachment; filename=output.xlsx",
                        'Content-Type': 'multipart/form-data'
                    },
                    responseType: 'arraybuffer',
                }
            ).then(async res => {
                const url = window.URL.createObjectURL(new Blob([res.data]));
                const link = document.createElement('a');
                link.href = url;
                link.setAttribute('download', 'output.xlsx');
                document.body.appendChild(link);
                link.click();
            }).catch(err => {
                console.log(err)
                alert(err)
            });
            setLoading(false)
        } catch (error) {
            console.log(error)
            setLoading(false)
        }
    }

    return (
        <div className={classes.root}>
            <span style={{ fontSize: '30px', marginBottom: '30px', textAlign: 'center', fontWeight: 'bold' }}>
                Input Supplier Price
            </span>
            <div style={{ justifyContent: 'center', alignItems: 'center', display: 'flex', flexDirection: 'column' }}>
                <div style={{color: 'black', fontSize: '15px' }}>
                    System will update the price if:
                    <br/>
                    1. MPN in quotation matches the MPN in price list
                    <br/>
                    2. Either of the following is true:
                    <br/>
                    a. If MOQ in price list = MOQ in quotation, then price at the exact MOQ in the price list will be updated.
                    <br/>
                    b. If the MOQ in the quotation does not exist in the price list, the price with the closest MOQ (lower than quotation MOQ) will be used.
                    <br/>
                    E.g. MOQ in quotation = 100, MOQ in price list: 10, 30, 50, 150.
                    <br/>
                    In the above scenario, the price for MOQ = 50 will be used to update the quotation.
                </div>
                <h3>Your Uploaded File <span style={{ fontWeight: 'bold', color: 'red', fontSize: '20px' }}>MUST</span> follow the following format: </h3>
                <img alt="Sample Format" src={require('../assets/Format.png')} width={"80%"} style={{ borderRadius: "10px" }} />
            </div>
            <div className={classes.fileUploadContainer} style={{ flexDirection: 'row', width: '60%' }}>
                <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>Quotation File</span>
                    <Input onChange={(event) => uploadInput(event)} type="file" className={classes.fileUpload} />
                </div>
                <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>Price List <span style={{color: "red"}}>(csv format only)</span></span>
                    <Input onChange={(event) => uploadPricelist(event)} type="file" className={classes.fileUpload} />
                </div>
            </div>
            <div style={{ marginTop: '50px' }}>
                <button onClick={() => postRequest()} className={classes.download}>
                    Compile
                </button>
            </div>
            <Backdrop
                sx={{ color: '#fff', zIndex: (theme) => theme.zIndex.drawer + 1 }}
                open={loading}
                style={{ position: 'absolute', zIndex: 10 }}
            >
                <CircularProgress color="inherit" />
            </Backdrop>
        </div>
    );
}

export default QuotationCompile;