import React, { useState } from 'react';
import { useStyles } from '../styles'
import { Backdrop, Checkbox, CircularProgress, FormControl, Input, InputLabel, MenuItem, Select } from '@material-ui/core';
import * as XLSX from 'xlsx';
import * as FileSaver from 'file-saver';

/*
    Step 1:
    upload stock file and upload removal list

    Step 2: if the MPN exists in removal list, then need to remove from the stock file

    step 3: have a checkbox that says "[  ]  Add website URL"
    ——
    Step 3A: if user ticks that checkbox, it will create a new column in the stock file with my website's url as:
    https://wiselink.com.sg/product/(mpnhere)

    E.g. https://wiselink.com.sg/product/115-1-A-5-1D/

    Condition: if the mpn contains / then it needs to alter to -
    Reason: / will make the link invalid. so we changed all / to -
    ——
    Step 3B: if user never tick the checkbox, then the url wont be added
*/
const Stock = () => {
    const classes = useStyles()
    const [remove, setRemove] = useState({}) // {MPN: [MPN, BRAND, STOCK]}
    const [stock, setStock] = useState({}) // {MPN: [MPN, BRAND]}
    const [check, setChecked] = useState(false)

    const uploadStock = (e) => {
        e.preventDefault();
        var files = e.target.files, f = files[0];
        var reader = new FileReader();
        reader.onload = function (e) {
            readRaw(e.target.result, 1)
        };
        reader.readAsBinaryString(f)
    }

    const uploadRemoval = (e) => {
        e.preventDefault();
        var files = e.target.files, f = files[0];
        var reader = new FileReader();
        reader.onload = function (e) {
            readRaw(e.target.result, 2)
        };
        reader.readAsBinaryString(f)
    }

    const readRaw = (data, num) => {
        let renderedData = XLSX.read(data, { type: 'binary' });
        const dataParse = XLSX.utils.sheet_to_json(renderedData.Sheets[renderedData.SheetNames[0]], { header: 1 });
        for (let i = 1; i < dataParse.length; i++) {
            if (num == 1) {
                stock[dataParse[i][0]] = dataParse[i]
            } else {
                remove[dataParse[i][0]] = dataParse[i]
            }
        }
    }

    const process = () => {
        console.log(Object.keys(stock).length)
        if (Object.keys(remove).length === 0 || Object.keys(stock).length === 0) {
            alert('ensure lists are uploaded')
            return
        }
        for (let key in remove) {
            if (key in stock) {
                delete stock[key]
                console.log('removed: ' + key)
            }
        }
        console.log(Object.keys(stock).length)

        /* Write and Download File */
        let wbData = []

        let myHeader = ['MPN', 'Brand', 'Stock']
        if (check) {
            myHeader.push('URL')
        }

        for (let key in stock) {
            let rowData = {}

            /* Part Name */
            rowData['MPN'] = stock[key][0]
            rowData['Brand'] = stock[key][1]
            rowData['Stock'] = stock[key][2]
            if (check) {
                rowData['URL'] = "https://wiselink.com.sg/product/" + key.replaceAll('/','-') + "/"
            }
            wbData.push(rowData)
        }

        const ws = XLSX.utils.json_to_sheet(wbData, { header: myHeader })
        let wb = { Sheets: { 'data': ws }, SheetNames: ['data'] }
        const excelBuffer = XLSX.write(wb, { bookType: 'xlsx', type: 'array' })
        const dd = new Blob([excelBuffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;charset=UTF-8' })
        FileSaver.saveAs(dd, 'Data.xlsx')
        setStock({})
        setRemove({})
    }

    return (
        <div className={classes.root}>
            <span style={{ fontSize: '30px', textAlign: 'center', fontWeight: 'bold' }}>
                Update Stock File
            </span>
            {/* <span style={{ fontSize: '18px', margin: '30px 0px 30px 0px', textAlign: 'left', fontWeight: "normal" }}>
                Quotation File Type = Export quotation from system <br/>
                Output file will follow the template of New Quotation. <br/>
                It will add in details from the old file if the CPN & MPN matches. <br/>
            </span> */}
            <div className={classes.fileUploadContainer} style={{ flexDirection: 'row', width: '60%' }}>
                <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>Stock File</span>
                    <Input onChange={(event) => uploadStock(event)} type="file" className={classes.fileUpload} />
                </div>
                <div className={classes.fileUploadWrapper} style={{ width: '30%' }}>
                    <span className={classes.label}>Removal list</span>
                    <Input onChange={(event) => uploadRemoval(event)} type="file" className={classes.fileUpload} />
                </div>
                <div style={{ flexDirection: 'row', width: '30%' }}>
                    <Checkbox value={check} onClick={() => setChecked(!check)} color={'primary'}/>
                    <span className={classes.label}>Add website URL</span>
                </div>
            </div>
            <div style={{ marginTop: '50px' }}>
                <button onClick={() => process()} className={classes.download}>
                    Update
                </button>
            </div>
        </div>
    );
}

export default Stock;